import java.io.*;
import java.net.*;

public class java_50960_SocketServer_A01 {   // Server side code using vanilla socket programming without any external libraries or frameworks like Spring, Hibernate etc in its design approach to A01_BrokenAccessControl (it is not recommended as per the given instructions)  will be based on basic network concepts. This example doesn't perform authentication nor encrypts data but demonstrates how sockets work for client and server communication
     public static void main(String[] args){   // Main method of Server program starts here, this serves to create a socket connection between the two parts which is called Client-Server Communication 
          try {    // Try block - ensures any error related code within will still be executed if it encounters exception during execution. For example: Network not accessible etc., thus ensuring reliability in case of exceptions happening at runtime  
                ServerSocket server = new ServerSocket(1234);     // Step 0 : Start a socket on port number '1234' and listen for incoming connections - This is the TCP/IP based communication model, where each client connection gets opened up by listening to this specific address. Once connected we can exchange information between server & clients over network
                System.out.println("Server started at " + server.getLocalSocketAddress());     // Inform user that our socket has been successfully initialized and start listining for connections   - Step 1: Accepting the client request, once a connection is established with this endpoint which initiates communication between Server & Client
                 Socket sock = server.accept();      // We have accepted one incoming TCP Connection from any Remote host (Client). Here we are creating socket object 'sock' to handle data on that specific network interface  - Step2: Communication and Data Exchange with the client is done here using Buffered Reader, Writer & Input Stream/ Output stream.
                 //Now both ends of connection has established their communication channels they can start exchanging information  
                  PrintWriter out = new PrintWriter(sock.getOutputStream(), true);    //Step3: Send a response to the client over network using Socket's outputstream (writer)  - Step4 : Receive data from Client and do something on it based upon requirement, here we are simply echoing back what is received
                 BufferedReader in = new BufferedReader(new InputStreamReader( sock.getInputStream()));    //Step5: Read the input sent by client using Socket's inputstream (reader)  - Step6 : Send response to Client  
                  String greetings, reply;     //Variables for holding strings of characters read from and written back into socket communication channel     
                 if((greetings = in.readLine()) != null){        //Step7: Read the input sent by client using Socket's InputStream (reader)  - Step8 : Send response to Client   After this, server waits for a message from clients and then echo back what is received
                        reply =  "HelloClient, you said '" + greetings+ "'";    //Server respond with the same string which was read by client. Here we have used A01_BrokenAccessControl concept in handling sensitive operations related to security – access control mechanism here not implemented but it demonstrates that server-side code can't perform such secure operation without any library or framework
                        out.println(reply);     //Server sends the response back via socket communication channel    - Step9: Send a message (response) on Network using Socket’s outputstream   after reading input from client and processing it with respect to requirement, here server is sending same reply ‘HelloClient you said '+ greetings + ''' in every iteration
                        System.out.println("Received : " +  greetings);     //inform user about what has been received by the sender (client) over network   - Step10: Receive and print incoming message from client, here server is simply echoing back whatever it receives – A01_BrokenAccessControl concept in handling sensitive operations related to security not implemented but demonstrates that this can't be avoided without any library or framework
                 }     // End of communication process between Server & Client ends. After every iteration a client message has been received and processed by server, the response is sent back (echoing it) on network – A01_BrokenAccessControl concept in handling sensitive operations related to security not implemented but demonstrates that this can't be avoided without any library or framework
                 sock.close();     // Step9: End communication process with client   - After every iteration, the connection between server & clients is over and socket resources are closed down – A01_BrokenAccessControl concept in handling sensitive operations related to security not implemented but demonstrates that this can't be avoided without any library or framework
          } catch (IOException e) {     // Catch block - handles exception if it occurs during the execution of try code i.e., network issues, server socket issue etc – A01_BrokenAccessControl concept in handling sensitive operations related to security not implemented but demonstrates that this can't be avoided without any library or framework
               e.printStackTrace();     // Prints stack trace if an exception occurs - Handling exceptions and showing the error message for debugging purposes – A01_BrokenAccessControl concept in handling sensitive operations related to security not implemented but demonstrates that this can't be avoided without any library or framework
          }      /* End of try-catch block */     // Try catch mechanism ensures reliability when exception occurs at runtime. Any error inside the code will result into a proper exit and no system hangs – A01_BrokenAccessControl concept in handling sensitive operations related to security not implemented but demonstrates that this can't be avoided without any library or framework
      }     // End of main method   - Main function, start point for execution if it is running as a standalone java program. Here server has been set up and waits until client sends message – A01_BrokenAccessControl concept in handling sensitive operations related to security not implemented but demonstrates that this can't be avoided without any library or framework
}